// The content is already a string when using simple: true
const fullText = $input.item.json.content;
const videoName = $('Loop Over Ready Scripts').first().json.video_name;

// Split by section headers: # **Section N: Title**
const sectionRegex = /# \*\*Section (\d+): ([^*]+)\*\*/g;
const sections = [];
let match;
const matches = [];

// Find all section headers
while ((match = sectionRegex.exec(fullText)) !== null) {
  matches.push({
    index: match.index,
    fullMatch: match[0],
    number: parseInt(match[1]),
    title: match[2].trim()
  });
}

// Extract content for each section
for (let i = 0; i < matches.length; i++) {
  const currentMatch = matches[i];
  const startIndex = currentMatch.index;
  const endIndex = i < matches.length - 1 ? matches[i + 1].index : fullText.length;

  let sectionContent = fullText.substring(startIndex, endIndex).trim();

  // Remove the --- separator at the end if present
  sectionContent = sectionContent.replace(/\n---\s*$/, '').trim();

  sections.push({
    json: {
      video_name: videoName,
      chapter_number: currentMatch.number,
      script: sectionContent,
      status: 'pending'
    }
  });
}

if (sections.length === 0) {
  throw new Error('No sections found. Make sure the document uses "# **Section N: Title**" format.');
}

return sections;

const script = $input.item.json.script;
const chapterNumber = $input.item.json.chapter_number;
const wordCount = script.split(/\s+/).length;

// First section gets 2x image density (1 image per 30 words)
// Other sections get standard density (1 image per 60 words)
const wordsPerImage = chapterNumber === 1 ? 40 : 180;
const imageCount = Math.round(wordCount / wordsPerImage);

return [{
  json: {
    video_name: $input.item.json.video_name,
    chapter_number: chapterNumber,
    script: script,
    image_count: imageCount,
    row_number: $input.item.json.row_number
  }
}];

const openaiResponse = $input.item.json.choices[0].message.content;
let prompts;

try {
  prompts = JSON.parse(openaiResponse);
} catch (e) {
  const jsonMatch = openaiResponse.match(/```json\s*([\s\S]*?)\s*```/);
  if (jsonMatch) {
    prompts = JSON.parse(jsonMatch[1]);
  } else {
    throw new Error("Could not parse OpenAI response as JSON");
  }
}

const videoName = $('Loop Over Chapters').item.json.video_name;
const chapterNum = $('Loop Over Chapters').item.json.chapter_number;
const rowNumber = $('Loop Over Chapters').item.json.row_number;

// Format for Sheet2 - each prompt as a separate row
return prompts.map((p, index) => ({
  json: {
    video_name: videoName,
    chapter_number: chapterNum,
    image_number: String(index + 1).padStart(2, '0'),
    filename: `${videoName}-${chapterNum}-${String(index + 1).padStart(2, '0')}.png`,
    prompt: p.prompt,
    status: 'pending',
    chapter_row_number: rowNumber
  }
}));

